// Fusionar todos los datos recopilados en un objeto unificado
const input    = $('Validar Formato TXN').item.json;
const txn      = $('Obtener Transacción').item.json;
const logsData = $('Obtener Logs').item.json;
const policies = $('Buscar Políticas').item.json;
const cases    = $('Buscar Casos Similares').item.json;
const sla      = $('Verificar SLA').item.json;

// Merchant: datos crudos de FastAPI + flags evaluados en n8n
const merchant = {
  ...$('Riesgo del Comercio').item.json,
  ...$('Evaluar Riesgo Comercio').item.json,
};

// Cliente: datos crudos de FastAPI + flags evaluados en n8n
const client = {
  ...$('Historial del Cliente').item.json,
  ...$('Evaluar Historial Cliente').item.json,
};

const slaStatus = sla.within_sla
  ? `dentro de SLA (${sla.days_elapsed}d / ${sla.sla_limit_days}d)`
  : `FUERA de SLA (${sla.days_elapsed}d / ${sla.sla_limit_days}d)`;

const agentAnalysis = [
  `Caso ${input.transaction_id}: ${txn.merchant}, USD ${txn.amount_usd},`,
  `canal ${txn.channel}, país ${txn.country}, score fraude ${txn.fraud_score}.`,
  `Motivo: ${input.motivo || 'no especificado'}.`,
  `SLA: ${slaStatus}.`,
  `Cliente VIP: ${input.cliente_vip ? 'sí' : 'no'}.`,
  `Políticas encontradas: ${(policies.results || []).length}.`,
  `Casos similares: ${(cases.results || []).length}.`,
].join(' ');

return [{
  json: {
    transaction_id:  input.transaction_id,
    motivo:          input.motivo,
    cliente_vip:     input.cliente_vip,
    tx_data:         txn,
    logs:            logsData.logs || [],
    policies:        policies.results || [],
    similar_cases:   cases.results || [],
    merchant_risk:   merchant,
    client_history:  client,
    sla:             sla,
    agent_analysis:  agentAnalysis,
  }
}];

// Construir el payload exacto que espera POST /api/reports/html (ReportRequest)
const ctx        = $('Compilar Contexto').item.json;
const resolution = $('Sintetizar Resolución').item.json;
const judge      = $input.first().json.judge_evaluation;

return [{
  json: {
    transaction:         ctx.tx_data,
    resolution:          resolution,
    judge_evaluation:    judge,
    agent_analysis:      ctx.agent_analysis,
    merchant_risk:       ctx.merchant_risk,
    client_profile:      ctx.client_history,
    logs:                ctx.logs,
    policies_evaluated:  ctx.policies,
    similar_cases:       ctx.similar_cases,
    hitl_decision:       null,
    cache_hit:           false,
    guardrail_warnings:  resolution.guardrail_warnings || [],
  }
}];

// El analista POSTea { decision: 'APPROVE'|'REJECT', notes: '...' } al resume_url
const resume     = $input.first().json;
const ctx        = $('Compilar Contexto').item.json;
const resolution = $('Sintetizar Resolución').item.json;
const judge      = $('Extraer Evaluación — Juez').item.json.judge_evaluation;

const hitlDecision = {
  analyst_decision: (resume.decision || 'APPROVE').toUpperCase(),
  analyst_notes:    resume.notes || '',
  final_outcome:    (resume.decision || 'APPROVE').toUpperCase() === 'REJECT' ? 'DENIED' : 'APPROVED',
  timestamp:        new Date().toISOString(),
};

return [{
  json: {
    transaction:         ctx.tx_data,
    resolution:          resolution,
    judge_evaluation:    judge,
    agent_analysis:      ctx.agent_analysis,
    merchant_risk:       ctx.merchant_risk,
    client_profile:      ctx.client_history,
    logs:                ctx.logs,
    policies_evaluated:  ctx.policies,
    similar_cases:       ctx.similar_cases,
    hitl_decision:       hitlDecision,
    cache_hit:           false,
    guardrail_warnings:  resolution.guardrail_warnings || [],
    _feedback_payload: {
      transaction_id:    ctx.transaction_id,
      analyst_decision:  hitlDecision.analyst_decision,
      analyst_notes:     hitlDecision.analyst_notes,
      final_outcome:     hitlDecision.final_outcome,
      judge_score:       judge.overall_score ?? 0,
    }
  }
}];
